#!/bin/sh
####################################################################################################################################
# Prepare the distribution so the tarball can be built and installed without the code generation or documentation tooling: generate
# the code files, copy the man pages and HTML documentation into doc, copy the distribution README, and write the dist marker that
# tells the build to use the shipped generated files.
#
# build-code reads its inputs from the source tree and writes the generated files into the distribution. The inputs come from the
# source rather than the distribution because src/build (the code generation sources) is excluded from the tarball. The read path
# is passed with a trailing component because build-code uses the parent directory of that argument as the repo root.
####################################################################################################################################
set -eu

build_code="$MESON_BUILD_ROOT/src/build-code"

if [ ! -x "$build_code" ]; then
    echo "dist: $build_code not found; run ninja before meson dist" >&2
    exit 1
fi

"$build_code" help "$MESON_SOURCE_ROOT/." "$MESON_DIST_ROOT"
"$build_code" postgres "$MESON_SOURCE_ROOT/." "$MESON_DIST_ROOT"

# Copy the man pages and HTML documentation generated by doc/release.pl --dist into doc/man and doc/html
mkdir -p "$MESON_DIST_ROOT/doc"

for doc in man html; do
    doc_src="$MESON_SOURCE_ROOT/doc/output/$doc"

    if [ ! -d "$doc_src" ]; then
        echo "dist: $doc_src not found; run 'doc/release.pl --dist' before meson dist" >&2
        exit 1
    fi

    cp -R "$doc_src" "$MESON_DIST_ROOT/doc/"
done

# Copy the distribution README into the tarball root
cp "$MESON_SOURCE_ROOT/doc/DIST.md" "$MESON_DIST_ROOT/README.md"

# Write the dist marker to the root. Its presence is what switches the build to the shipped generated files; it records the version
# for traceability.
version=$(basename "$MESON_DIST_ROOT")
echo "${version#pgbackrest-}" > "$MESON_DIST_ROOT/dist"
